## 4. 비동기 처리

### 4.1 매칭 알고리즘 비동기화

```kotlin
// Before: 동기 처리 (클라이언트 대기)
@MutationMapping
fun requestMatch(userId: String): MatchResult {
    return matchingService.findMatch(userId) // 최대 3초 대기
}

// After: 비동기 + WebSocket/SSE 푸시
@MutationMapping
fun requestMatch(userId: String): RequestMatchResult {
    // 즉시 반환 (대기열 등록만)
    val queueId = matchingService.enqueueAndMatchAsync(userId)
    return RequestMatchResult(queueId = queueId, status = "QUEUED")
}

@Service
class CallMatchingService(
    private val applicationEventPublisher: ApplicationEventPublisher
) {
    @Async("matchingExecutor")
    fun enqueueAndMatchAsync(userId: String): CompletableFuture<String> {
        val queueEntry = callQueueRepository.save(
            CallQueueEntity(userId = userId, status = WAITING)
        )

        // 비동기로 매칭 시도
        val matched = tryMatch(queueEntry)
        if (matched != null) {
            applicationEventPublisher.publishEvent(
                MatchFoundEvent(requesterId = userId, matchedUserId = matched.userId)
            )
        }

        return CompletableFuture.completedFuture(queueEntry.id)
    }
}

// ThreadPool 설정
@Configuration
class AsyncConfig {
    @Bean("matchingExecutor")
    fun matchingExecutor(): Executor = ThreadPoolTaskExecutor().apply {
        corePoolSize = 10
        maxPoolSize = 50
        queueCapacity = 200
        setThreadNamePrefix("matching-")
        initialize()
    }
}
```

