## 3. 쿼리 최적화

### 3.1 QueryDSL Projection으로 필요한 컬럼만 조회

```kotlin
// Before: Entity 전체 로드
fun findWaitingUsers(): List<CallQueueEntity> {
    return callQueueRepository.findByStatus(WAITING) // 모든 컬럼 조회
}

// After: Projection으로 필요 필드만
data class MatchCandidateDto(
    val userId: String,
    val gender: Int,
    val ageGroup: Int,
    val waitingSeconds: Long
)

// QueryDSL Repository 구현
class CallQueueQueryRepositoryImpl(
    private val queryFactory: JPAQueryFactory
) : CallQueueQueryRepository {

    override fun findMatchCandidates(
        excludeUserId: String,
        criteria: MatchCriteria
    ): List<MatchCandidateDto> {
        val queue = QCallQueueEntity.callQueueEntity

        return queryFactory
            .select(
                Projections.constructor(
                    MatchCandidateDto::class.java,
                    queue.userId,
                    queue.gender,
                    queue.ageGroup,
                    Expressions.numberTemplate(
                        Long::class.java,
                        "TIMESTAMPDIFF(SECOND, {0}, NOW())",
                        queue.createdAt
                    )
                )
            )
            .from(queue)
            .where(
                queue.status.eq(WAITING),
                queue.userId.ne(excludeUserId),
                queue.gender.`in`(criteria.targetGenders),
                queue.createdAt.gt(LocalDateTime.now().minusMinutes(10)) // 10분 이상 대기자 제외
            )
            .orderBy(queue.createdAt.asc()) // 오래 기다린 사람 우선
            .limit(20)
            .fetch()
    }
}
```

